// For each route, get new prospects that haven't been contacted
const routes = $input.all().map(item => item.json);
const tasks = [];

for (const route of routes) {
  tasks.push({
    json: {
      route_id: route.route_id,
      route_number: route.route_number,
      zip_code: route.zip_code,
      spaces_available: route.spaces_available,
      city: route.city,
      state: route.state_code
    }
  });
}

return tasks;

// Generate personalized email for each prospect
const prospects = $input.all();
const routeInfo = $('Prepare Route Tasks').first().json;

const emails = prospects.map(item => {
  const p = item.json;
  const firstName = p.contact_name ? p.contact_name.split(' ')[0] : 'Business Owner';
  const bizName = p.business_name;
  const city = routeInfo.city;
  const routeNum = routeInfo.route_number;
  const zip = routeInfo.zip_code;
  const spacesLeft = routeInfo.spaces_available;

  const subject = `Quick question about ${bizName}`;

  const body = `Hey ${firstName},

I'm putting together a community mailer for ${city} — specifically for the ${zip} area (Route ${routeNum}). It's a large 9x12 postcard that goes to every single doorstep in that postal route via USPS.

We're offering local businesses in ${zip} a chance to get their ad in front of thousands of households for a fraction of what normal advertising costs.

The mailer hits ${city} homes directly — no digital scrolling, no ad blockers, just real people seeing your business in their hands.

We have ${spacesLeft} ad spaces left for Route ${routeNum} and I wanted to give ${bizName} first shot at one before we fill up.

Interested in hearing more? Just reply to this email and I'll send over the details.

— Ryan Harrell
Mailhouse Media
(910) XXX-XXXX`;

  return {
    json: {
      prospect_id: p.id,
      route_id: routeInfo.route_id,
      to_email: p.email,
      to_name: p.contact_name || bizName,
      business_name: bizName,
      subject: subject,
      body: body,
      sequence_step: 1,
      city: city,
      route_number: routeNum,
      zip_code: zip
    }
  };
});

return emails;
